solution: class Solution {
public:
    bool uniqueOccurrences(vector<int>& arr) {
        int freq[2001] = {0};
        for (int v : arr) ++freq[v + 1000];
        bool seen[1001] = {false};
        for (int i = 0; i <= 2000; ++i) {
            int f = freq[i];
            if (f == 0) continue;
            if (seen[f]) return false;
            seen[f] = true;
        }
        return true;
    }
};
